### Step 2: Define the `Board` class

```python
class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("black")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("white")

    def display(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else "." for piece in row))
        print()

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, from_row, from_col, to_row, to_col):
        piece = self.get_piece(from_row, from_col)
        self.board[from_row][from_col] = None
        if abs(to_row - from_row) == 2:
            # Remove captured piece
            mid_row, mid_col = (from_row + to_row) // 2, (from_col + to_col) // 2
            self.board[mid_row][mid_col] = None
        self.board[to_row][to_col] = piece

    def is_valid_move(self, from_row, from_col, to_row, to_col):
        piece = self.get_piece(from_row, from_col)
        if not piece:
            return False
        if (piece.color == "black" and to_row >= piece.color) or (piece.color == "white" and to_row <= piece.color):
            return False
        row_diff = abs(to_row - from_row)
        col_diff = abs(to_col - from_col)
        if row_diff != 1 and row_diff != 2:
            return False
        if col_diff != 1:
            return False
        if row_diff == 2:
            mid_row, mid_col = (from_row + to_row) // 2, (from_col + to_col) // 2
            if not self.get_piece(mid_row, mid_col):
                return False
        if piece.king and col_diff != 1:
            return False
        return True

    def is_in_bounds(self, row, col):
        return 0 <= row < 8 and 0 <= col < 8
